<!DOCTYPE html>
<html>
<head>
    <title>Librairie - Calcul commande</title>
</head>
<body>
    <h2>Commande de livres</h2>
    Nombre de livres : <input type="number" id="quantite"><br>
    Prix unitaire (FCFA) : <input type="number" id="prix"><br>
    <button onClick="calculerTotal()">Calculer</button>
    <p id="resultat"></p>

    <script>
        function calculerTotal() {
            // Récupération des valeurs
            let quantite = parseFloat(document.getElementById('quantite').value);
            let prixUnitaire = parseFloat(document.getElementById('prix').value);

            // Vérification des saisies
            if (isNaN(quantite) || isNaN(prixUnitaire) || quantite <= 0 || prixUnitaire <= 0) {
                document.getElementById('resultat').innerHTML = "Veuillez saisir des nombres positifs valides.";
                return;
            }

            // Calcul du total brut
            let totalBrut = quantite * prixUnitaire;
            let totalNet = totalBrut;

            // Application de la réduction
            if (totalBrut > 20000) {
                totalNet = totalBrut * 0.9; // 10% de réduction
            }

            // Affichage du résultat
            document.getElementById('resultat').innerHTML = "Total à payer : " + totalNet.toFixed(2) + " FCFA";
        }
    </script>
</body>
</html>
